-- (2) Prefill the four June weeks
-- 1–5 June  (2026-06-01 -> 2026-06-05) - 68 entries
DO $$
DECLARE pid uuid;
BEGIN
  SELECT id INTO pid FROM production.roster_periods WHERE name = '1–5 June';
  IF pid IS NULL THEN INSERT INTO production.roster_periods (name,start_date,end_date) VALUES ('1–5 June','2026-06-01','2026-06-05') RETURNING id INTO pid; END IF;
  DELETE FROM production.roster_entries WHERE period_id = pid;
END $$;

